use crate::decoders::{Crack, CrackResult, Decoder, check_string_success};use crate::checkers::CheckerTypes;use std::marker::PhantomData;pub struct A1Z26Decoder;impl Crack for Decoder<A1Z26Decoder> {    fn crack(&self, text: &str, checker: &CheckerTypes) -> CrackResult {        let mut result = CrackResult::new(self.get_name(), self.get_description(), self.get_link());        result.encrypted_text = text.to_string();        let cleaned: String = text.chars().filter(|c| c.is_ascii_digit() || *c == ' ' || *c == '-' || *c == ',').collect();        let parts: Vec<&str> = cleaned.split(|c: char| c == ' ' || c == ',').collect();        let mut decoded = String::new();        for part in &parts {            let part = part.trim().trim_start_matches('-').trim_end_matches('-');            if part.is_empty() { continue; }            if let Ok(num) = part.parse::<u32>() {                if num >= 1 && num <= 26 {                    decoded.push((b'a' + (num as u8 - 1)) as char);                } else {                    return result;                }            } else {                return result;            }        }        if !decoded.is_empty() && check_string_success(&decoded, text) {            let check_result = checker.check_text(&decoded);            if check_result.is_identified {                result.success = true;                result.unencrypted_text = Some(vec![decoded]);                result.checker_name = check_result.checker_name;            }        }        result    }    fn get_name(&self) -> &'static str { "A1Z26" }    fn get_popularity(&self) -> f32 { 0.3 }    fn get_tags(&self) -> &'static [&'static str] { &["a1z26", "decoder", "cipher"] }    fn get_description(&self) -> &'static str { "A1Z26 maps numbers 1-26 to letters A-Z respectively." }    fn get_link(&self) -> &'static str { "https://en.wikipedia.org/wiki/Letter_numbers" }}impl Decoder<A1Z26Decoder> {    pub fn new() -> Self {        Decoder {            name: "A1Z26",            description: "A1Z26 maps numbers 1-26 to letters A-Z respectively.",            link: "https://en.wikipedia.org/wiki/Letter_numbers",            tags: vec!["a1z26", "decoder", "cipher"],            popularity: 0.3,            phantom: PhantomData,        }    }}



